using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args.Length > 0 ? args[0] : "../build.binlog";
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD SUMMARY ===");
Console.WriteLine($"Build Succeeded: {build.Succeeded}");
Console.WriteLine();

// Collect all errors and warnings
var errors = new List<(string Project, string File, int Line, int Col, string Code, string Message, string Subcategory)>();
var warnings = new List<(string Project, string File, int Line, int Col, string Code, string Message)>();
var projectResults = new Dictionary<string, bool>();

void Walk(BaseNode node, string currentProject = "")
{
    if (node is Project p)
    {
        currentProject = p.Name ?? p.ProjectFile ?? "";
    }
    else if (node is Target t)
    {
        // keep currentProject
    }

    if (node is Error err)
    {
        errors.Add((currentProject, err.File ?? "", err.LineNumber ?? 0, err.ColumnNumber ?? 0, err.Code ?? "", err.Text ?? err.ToString(), err.Subcategory ?? ""));
    }
    else if (node is Warning warn)
    {
        warnings.Add((currentProject, warn.File ?? "", warn.LineNumber ?? 0, warn.ColumnNumber ?? 0, warn.Code ?? "", warn.Text ?? warn.ToString()));
    }

    if (node is TreeNode treeNode)
    {
        foreach (var child in treeNode.Children)
        {
            if (child is BaseNode childNode)
                Walk(childNode, currentProject);
        }
    }
}

Walk(build);

// Print errors grouped by project
Console.WriteLine($"=== ERRORS ({errors.Count} total) ===");
var errorsByProject = errors.GroupBy(e => e.Project).OrderBy(g => g.Key);
foreach (var group in errorsByProject)
{
    Console.WriteLine($"\n--- Project: {group.Key} ---");
    foreach (var e in group)
    {
        var location = !string.IsNullOrEmpty(e.File) ? $"{Path.GetFileName(e.File)}({e.Line},{e.Col})" : "(no location)";
        Console.WriteLine($"  [{e.Code}] {location}: {e.Message}");
    }
}

Console.WriteLine($"\n=== WARNINGS ({warnings.Count} total) ===");
var warningsByProject = warnings.GroupBy(w => w.Project).OrderBy(g => g.Key);
foreach (var group in warningsByProject)
{
    Console.WriteLine($"\n--- Project: {group.Key} ---");
    foreach (var w in group)
    {
        var location = !string.IsNullOrEmpty(w.File) ? $"{Path.GetFileName(w.File)}({w.Line},{w.Col})" : "(no location)";
        Console.WriteLine($"  [{w.Code}] {location}: {w.Message}");
    }
}

// Look at project structure - which projects reference which
Console.WriteLine("\n=== PROJECT STRUCTURE ===");
void WalkProjects(BaseNode node, int depth = 0)
{
    if (node is Project proj)
    {
        var succeeded = proj.Succeeded;
        var status = succeeded ? "OK" : "FAILED";
        Console.WriteLine($"{new string(' ', depth * 2)}[{status}] {proj.Name} ({Path.GetFileName(proj.ProjectFile ?? "")})");
    }
    if (node is TreeNode tn)
    {
        foreach (var child in tn.Children)
        {
            if (child is BaseNode bn)
                WalkProjects(bn, node is Project ? depth + 1 : depth);
        }
    }
}
